#include <iostream>
#include <string>
using namespace std;

int main() {
    // 1. Статичний масив з 5 елементів
    int scores[5] = {90, 85, 78, 92, 88};

    // Алгоритм пошуку максимального значення
    int maxScore = scores[0]; // Припускаємо, що перший - найбільший
    for (int i = 1; i < 5; i++) {
        if (scores[i] > maxScore) {
            maxScore = scores[i]; // Оновлюємо, якщо знайшли більший
        }
    }
    cout << "Рекорд: " << maxScore << endl;

    // 2. Двовимірний масив (матриця 2 рядки, 3 стовпці)
    int map[2][3] = {
        {1, 2, 3},
        {4, 5, 6}
    };
    cout << "Елемент [1][2] (другий рядок, третій стовпець): " << map[1][2] << endl;

    // 3. Робота з string як з масивом
    string word = "Programming";
    cout << "Слово містить " << word.length() << " літер." << endl;
    cout << "Перша літера: " << word[0] << endl;
    cout << "Остання літера: " << word[word.length() - 1] << endl; // НІКОДИ не вказуйте word.length(), розмір-1!

    return 0;
}
